import React, { useEffect, useState } from "react";
import api from "../api";
import { motion } from "framer-motion";

export default function TodayDashboard() {
  const [todayFoods, setTodayFoods] = useState([]);

  useEffect(() => {
    const fetchDashboard = async () => {
      const res = await api.get("/foods/today"); // only available foods
      setTodayFoods(res.data);
    };
    fetchDashboard();
  }, []);

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-100 to-slate-200 p-6">
      <div className="max-w-6xl mx-auto">
        <h1 className="text-3xl font-bold mb-8 text-center text-slate-800">
          🍽️ Today’s Menu
        </h1>

        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6">
          {todayFoods.length === 0 && (
            <div className="col-span-full text-center text-gray-500 text-lg">
              No foods marked for today.
            </div>
          )}

          {todayFoods.map((food, index) => (
            <motion.div
              key={food._id}
              className="bg-white border rounded-2xl shadow-lg p-5 flex flex-col items-center hover:shadow-2xl cursor-pointer"
              initial={{ opacity: 0, y: 40 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
              whileHover={{ scale: 1.05, rotate: 1 }}
              whileTap={{ scale: 0.95 }}
            >
              {food.img && (
                <motion.img
                  src={`/uploads/${food.img}`}
                  alt={food.name}
                  className="w-28 h-28 object-cover rounded-xl mb-4"
                  whileHover={{ scale: 1.1 }}
                  transition={{ duration: 0.3 }}
                />
              )}
              <div className="font-semibold text-lg text-slate-700">
                {food.name}
              </div>
              <div className="text-sm text-gray-500 mb-2">₹{food.price}</div>

              <motion.button
                className="px-4 py-2 bg-green-500 text-white text-sm font-medium rounded-full shadow hover:bg-green-600"
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
              >
                Order Now
              </motion.button>
            </motion.div>
          ))}
        </div>
      </div>
    </div>
  );
}
